arguments.file_text:
@page "/apply"
@using sv_a1ca32c91ddd4918b44c237172a2e6bb.Models
@inject IApplicationService ApplicationService
@rendermode InteractiveServer

<PageTitle>Job Application</PageTitle>

<h1 class="mb-4">Job Application</h1>

@* ───────── Step Indicator Bar ───────── *@
<nav class="d-flex justify-content-between mb-4 position-relative" aria-label="Application steps">
    @for (int i = 0; i < StepLabels.Length; i++)
    {
        var step = i;
        var isCurrent = step == _currentStep;
        var isCompleted = step < _currentStep && !_submitted;

        <button type="button"
                class="btn btn-link text-decoration-none text-center flex-fill p-2 @(isCurrent ? "fw-bold text-primary" : isCompleted ? "text-success" : "text-muted")"
                disabled="@(!isCompleted || _submitted)"
                @onclick="() => GoToStep(step)">
            <div>
                @if (isCompleted)
                {
                    <span class="badge rounded-pill bg-success me-1">✓</span>
                }
                else
                {
                    <span class="badge rounded-pill @(isCurrent ? "bg-primary" : "bg-secondary") me-1">@(step + 1)</span>
                }
                @StepLabels[step]
            </div>
        </button>

        @if (i < StepLabels.Length - 1)
        {
            <div class="d-flex align-items-center text-muted px-1">→</div>
        }
    }
</nav>

<hr />

@if (!string.IsNullOrEmpty(_errorMessage))
{
    <div class="alert alert-danger" role="alert">@_errorMessage</div>
}

@* ───────── Step 1: Personal Info ───────── *@
@if (_currentStep == 0)
{
    <h3>Personal Information</h3>

    <div class="mb-3">
        <label class="form-label">Full Name <span class="text-danger">*</span></label>
        <input type="text" class="form-control" @bind="_fullName" />
    </div>
    <div class="mb-3">
        <label class="form-label">Email <span class="text-danger">*</span></label>
        <input type="email" class="form-control" @bind="_email" />
    </div>
    <div class="mb-3">
        <label class="form-label">Phone <span class="text-danger">*</span></label>
        <input type="tel" class="form-control" @bind="_phone" />
    </div>
    <div class="mb-3">
        <label class="form-label">Address <span class="text-danger">*</span></label>
        <textarea class="form-control" rows="2" @bind="_address"></textarea>
    </div>

    <div class="d-flex justify-content-end">
        <button class="btn btn-primary" @onclick="NextFromPersonalInfo" disabled="@_isLoading">
            @if (_isLoading) { <span class="spinner-border spinner-border-sm me-1"></span> }
            Next
        </button>
    </div>
}

@* ───────── Step 2: Work History ───────── *@
@if (_currentStep == 1)
{
    <h3>Work History</h3>

    @for (int i = 0; i < _workEntries.Count; i++)
    {
        var idx = i;
        <div class="card mb-3">
            <div class="card-body">
                <div class="d-flex justify-content-between align-items-center mb-2">
                    <h5 class="card-title mb-0">Position @(idx + 1)</h5>
                    @if (_workEntries.Count > 1)
                    {
                        <button class="btn btn-outline-danger btn-sm" @onclick="() => RemoveWorkEntry(idx)">Remove</button>
